import React, { useState } from "react";
import axios from "axios";
import Api from "../api/Api";

function Login() {
  const [email, setEmail] = useState("");
  const [otp, setOtp] = useState("");
  const [showOtp, setShowOtp] = useState(false);

  const sendOtp = async () => {
    try {
      const res = await axios.post(
        Api.send_otp,
        { email }
      );

      alert(res.data.message);
      setShowOtp(true);

    } catch (error) {

      alert(
        error.response?.data?.message ||
        "Failed to send OTP"
      );

    }
  };

  const verifyOtp = async () => {
    try {

      const res = await axios.post(
        Api.verify_otp,
        {
          email,
          otp,
        }
      );

      localStorage.setItem(
        "token",
        res.data.token
      );

      localStorage.setItem(
        "role",
        res.data.role
      );

      alert("Login Successful");

      if (res.data.role === "driver") {
        window.location.href =
          "/driver-dashboard";
      }

      else if (
        res.data.role === "supervisor"
      ) {
        window.location.href =
          "/supervisor-dashboard";
      }

      else if (
        res.data.role === "admin"
      ) {
        window.location.href =
          "/admin";
      }

    } catch (error) {

      alert(
        error.response?.data?.message ||
        "OTP Verification Failed"
      );

    }
  };

  return (
    <div className="min-h-screen bg-[#4CBB17]/20 flex items-center justify-center px-4">

      <div className="bg-white shadow-lg rounded-xl p-8 w-full max-w-md">

        {/* Logo */}
      <h1 className="flex items-center gap-3 text-5xl font-extrabold text-green-900">
  <img
    src="garbageVehicle.jpeg"
    alt="CleanTrack Logo"
    className="w-16 h-16 object-contain"
  />

  CleanTrack
</h1>

        <p className="text-center text-gray-500 mt-2 mb-6">
          User Login
        </p>

        {!showOtp ? (
          <>
            {/* Mobile Input */}

            <div className="mb-4">
              <label className="block text-sm font-medium mb-1">
                Email ID
              </label>

              <input
                type="email"
                placeholder="Enter Email ID"
                value={email}
                onChange={(e) =>
                  setMobile(e.target.value)
                }
                className="w-full border rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-green-500"
              />
            </div>

            <button
              onClick={sendOtp}
              className="w-full bg-green-600 text-white py-2 rounded-lg font-semibold hover:bg-green-700 transition"
            >
              Send OTP
            </button>
          </>
        ) : (
          <>
            {/* Mobile Display */}

            <div className="bg-green-50 border border-green-200 rounded-lg p-3 mb-4">

              <p className="text-center text-green-700 text-sm">
                OTP sent to
              </p>

              <p className="text-center font-semibold text-gray-800">
                {email}
              </p>

            </div>

            {/* OTP Input */}

            <div className="mb-4">
              <label className="block text-sm font-medium mb-1">
                Enter OTP
              </label>

              <input
                type="text"
                maxLength="6"
                placeholder="Enter 6 Digit OTP"
                value={otp}
                onChange={(e) =>
                  setOtp(e.target.value)
                }
                className="w-full border rounded-lg px-4 py-2 text-center tracking-widest text-lg focus:outline-none focus:ring-2 focus:ring-green-500"
              />
            </div>

            <button
              onClick={verifyOtp}
              className="w-full bg-green-600 text-white py-2 rounded-lg font-semibold hover:bg-green-700 transition"
            >
              Verify OTP & Login
            </button>
          </>
        )}

      </div>
    </div>
  );
}

export default Login;
